var LEFT_START = "left-start";
var LEFT_END = "left-end";

// src/components/pg/tooltip/addTooltip.ts
function addTooltip($part, render2, position) {
  function handleMouseEnter() {
    $part.dispatchEvent(
      new CustomEvent("tooltip", {
        detail: {
          visible: true,
          rect: $part.getBoundingClientRect(),
          text: render2(),
          position: position ?? BOTTOM
        },
        bubbles: true,
        composed: true
      })
    );
  }
  function handleMouseLeave() {
    $part.dispatchEvent(
      new CustomEvent("tooltip", {
        detail: {
          visible: false
        },
        bubbles: true,
        composed: true
      })
    );
  }
  $part.addEventListener("mouseenter", handleMouseEnter);
  $part.addEventListener("mouseleave", handleMouseLeave);
}

