// src/components/pg/shared/filter.ts
function* filter(array, condition, maxSize) {
  if (!maxSize || maxSize > array.length) {
    maxSize = array.length;
  }
  let count = 0;
  let i = 0;
  while (count < maxSize && i < array.length) {
    if (condition(array[i])) {
      yield array[i];
      count++;
    }
    i++;
  }
}

// src/components/pg/shared/iconFilter.ts
function exactMatch(icons2, term) {
  for (var i = 0, c = icons2.length; i < c; i++) {
    if (icons2[i].name?.toLowerCase() === term) {
      icons2.unshift(icons2.splice(i, 1)[0]);
      return icons2;
    }
  }
  return icons2;
}
function sanitizeTerm(term) {
  return removeDiacritics(term.trim().toLowerCase()).replace(/(\w) (\w)/g, "$1-$2");
}
function iconFilter(icons2, term, limit = 5) {
  term = sanitizeTerm(term);
  const iconsByName = filter(
    icons2,
    (icon) => {
      return icon.name?.toLowerCase().indexOf(term) === 0;
    },
    limit
  );
  const list4 = Array.from(iconsByName);
  let skip = list4.map((icon) => icon.id);
  if (list4.length < limit) {
    var more = filter(
      icons2,
      (icon) => {
        if (skip.includes(icon.id)) {
          return false;
        }
        return icon.name?.toLowerCase().indexOf(term) !== -1;
      },
      limit - list4.length
    );
    var more2 = Array.from(more);
    more2.forEach((icon) => list4.push(icon));
  }
  skip = list4.map((icon) => icon.id);
  if (list4.length < limit) {
    var iconsByAliases = filter(
      icons2,
      (icon) => {
        if (skip.includes(icon.id)) {
          return false;
        }
        for (var i = 0, c = icon.aliases.length; i < c; i++) {
          if (icon.aliases[i].name == null) {
            console.error(`Invalid alias in ${icon.name}`);
            return false;
          }
          if (icon.aliases[i].name.indexOf(term) !== -1) {
            icon.aliases[i].match = true;
            return true;
          }
        }
        return false;
      },
      limit - list4.length
    );
    const list22 = Array.from(iconsByAliases);
    list22.forEach((icon) => list4.push(icon));
  }
  return exactMatch(list4, term);
}

