var REMOVE = "pgtoastremove";
function observeToasts({ add, remove }) {
  document.body.addEventListener(ADD, (e) => {
    add(e.detail);
  });
  document.body.addEventListener(REMOVE, (e) => {
    remove(e.detail.key);
  });
}
function addToast(config2) {
  config2.key = config2.key || uuid();
  const event = new CustomEvent(ADD, {
    detail: config2
  });
  document.body.dispatchEvent(event);
  setTimeout(() => {
    removeToast(config2.key);
  }, config2.seconds * 1e3);
  return config2.key;
}
function removeToast(key) {
  const event = new CustomEvent(REMOVE, {
    detail: { key }
  });
  document.body.dispatchEvent(event);
}
function addInfoToast(message, seconds = 3) {
  const type3 = "info";
  return addToast({ type: type3, message, seconds });
}

